import{_ as a,c as i,o as t,ag as e}from"./chunks/framework.DK1-H3E1.js";const p=JSON.parse('{"title":"Ollama 入门：本地运行大模型的工程实践","description":"","frontmatter":{"order":21},"headers":[],"relativePath":"ai/ollama.md","filePath":"ai/ollama.md","lastUpdated":1772197851000}'),r={name:"ai/ollama.md"};function o(h,l,d,n,u,s){return t(),i("div",null,l[0]||(l[0]=[e('<h1 id="ollama-入门-本地运行大模型的工程实践" tabindex="-1">Ollama 入门：本地运行大模型的工程实践 <a class="header-anchor" href="#ollama-入门-本地运行大模型的工程实践" aria-label="Permalink to &quot;Ollama 入门：本地运行大模型的工程实践&quot;">​</a></h1><blockquote><p>📅 主题：Ollama 的核心概念、部署方式与常见用法</p></blockquote><h2 id="一、什么是-ollama" tabindex="-1">一、什么是 Ollama <a class="header-anchor" href="#一、什么是-ollama" aria-label="Permalink to &quot;一、什么是 Ollama&quot;">​</a></h2><p><strong>Ollama</strong> 是一个面向本地环境的大模型运行与管理工具。<br> 它让你可以在本机（或私有服务器）快速拉取、运行、管理 LLM，而不必每次都依赖云端 API。</p><p>一句话理解：<br><strong>Ollama = 本地模型运行时 + 模型管理 + 简单 API 服务层。</strong></p><hr><h2 id="二、为什么很多团队选择-ollama" tabindex="-1">二、为什么很多团队选择 Ollama <a class="header-anchor" href="#二、为什么很多团队选择-ollama" aria-label="Permalink to &quot;二、为什么很多团队选择 Ollama&quot;">​</a></h2><ol><li><p><strong>数据可控</strong></p><ul><li>推理在本地/私有网络完成，敏感数据不出域</li></ul></li><li><p><strong>离线可用</strong></p><ul><li>内网或无外网环境也可使用（模型已下载情况下）</li></ul></li><li><p><strong>上手成本低</strong></p><ul><li>安装、拉模型、运行都很直接，CLI 友好</li></ul></li><li><p><strong>统一接口</strong></p><ul><li>提供本地 HTTP API，方便接入现有应用</li></ul></li><li><p><strong>适合原型与中小规模部署</strong></p><ul><li>对个人开发、团队 PoC、内部工具很友好</li></ul></li></ol><hr><h2 id="三、核心概念" tabindex="-1">三、核心概念 <a class="header-anchor" href="#三、核心概念" aria-label="Permalink to &quot;三、核心概念&quot;">​</a></h2><h2 id="_3-1-模型-model" tabindex="-1">3.1 模型（Model） <a class="header-anchor" href="#_3-1-模型-model" aria-label="Permalink to &quot;3.1 模型（Model）&quot;">​</a></h2><p>Ollama 通过模型名管理不同模型版本，例如常见开源模型系列。<br> 你可以理解为“可运行的模型镜像”。</p><h2 id="_3-2-modelfile" tabindex="-1">3.2 Modelfile <a class="header-anchor" href="#_3-2-modelfile" aria-label="Permalink to &quot;3.2 Modelfile&quot;">​</a></h2><p><code>Modelfile</code> 类似 Dockerfile，用于定义“如何构建一个可运行模型”，包括：</p><ul><li>基础模型来源</li><li>系统提示（system）</li><li>参数设置（温度、上下文长度等）</li><li>模板格式</li></ul><p>这让模型行为可版本化、可复现。</p><h2 id="_3-3-本地-api-服务" tabindex="-1">3.3 本地 API 服务 <a class="header-anchor" href="#_3-3-本地-api-服务" aria-label="Permalink to &quot;3.3 本地 API 服务&quot;">​</a></h2><p>Ollama 启动后可通过本地接口调用模型，常见能力：</p><ul><li>对话生成</li><li>流式输出</li><li>嵌入向量生成（部分模型/配置）</li></ul><hr><h2 id="四、基础工作流" tabindex="-1">四、基础工作流 <a class="header-anchor" href="#四、基础工作流" aria-label="Permalink to &quot;四、基础工作流&quot;">​</a></h2><p>典型流程：</p><ol><li>安装 Ollama</li><li>拉取模型（pull）</li><li>运行模型（run）</li><li>通过 CLI 或 HTTP API 调用</li><li>按业务需求调整 Modelfile 与参数</li></ol><p>这个流程非常适合快速验证 Prompt、RAG、Agent 等能力。</p><hr><h2 id="五、在应用系统中的常见接入方式" tabindex="-1">五、在应用系统中的常见接入方式 <a class="header-anchor" href="#五、在应用系统中的常见接入方式" aria-label="Permalink to &quot;五、在应用系统中的常见接入方式&quot;">​</a></h2><h2 id="_5-1-本地开发模式" tabindex="-1">5.1 本地开发模式 <a class="header-anchor" href="#_5-1-本地开发模式" aria-label="Permalink to &quot;5.1 本地开发模式&quot;">​</a></h2><ul><li>前端/后端直接调用本机 Ollama API</li><li>快速调试 Prompt 与模型行为</li></ul><h2 id="_5-2-局域网服务模式" tabindex="-1">5.2 局域网服务模式 <a class="header-anchor" href="#_5-2-局域网服务模式" aria-label="Permalink to &quot;5.2 局域网服务模式&quot;">​</a></h2><ul><li>在一台有 GPU 的机器上部署 Ollama</li><li>其他服务通过内网调用</li></ul><h2 id="_5-3-与框架集成" tabindex="-1">5.3 与框架集成 <a class="header-anchor" href="#_5-3-与框架集成" aria-label="Permalink to &quot;5.3 与框架集成&quot;">​</a></h2><ul><li>可接入 LangChain / LlamaIndex / 自研 Agent 编排层</li><li>用于本地 RAG、工具调用、文档问答等场景</li></ul><hr><h2 id="六、ollama-与云端-api-的取舍" tabindex="-1">六、Ollama 与云端 API 的取舍 <a class="header-anchor" href="#六、ollama-与云端-api-的取舍" aria-label="Permalink to &quot;六、Ollama 与云端 API 的取舍&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>Ollama（本地）</th><th>云端 API</th></tr></thead><tbody><tr><td>数据隐私</td><td>更强（本地可控）</td><td>依赖云供应商策略</td></tr><tr><td>启动成本</td><td>低到中（需本地算力）</td><td>低（无需本地算力）</td></tr><tr><td>扩容能力</td><td>受本地资源限制</td><td>弹性更强</td></tr><tr><td>运维复杂度</td><td>中（需自管模型与机器）</td><td>相对低</td></tr><tr><td>单次延迟</td><td>本地近端通常较低</td><td>受网络与服务负载影响</td></tr></tbody></table><p>常见策略是混合架构：</p><ul><li>敏感任务走本地 Ollama</li><li>高峰或高复杂任务走云端大模型</li></ul><hr><h2 id="七、性能与稳定性建议" tabindex="-1">七、性能与稳定性建议 <a class="header-anchor" href="#七、性能与稳定性建议" aria-label="Permalink to &quot;七、性能与稳定性建议&quot;">​</a></h2><ol><li><p><strong>选型先看任务，不只看参数量</strong></p><ul><li>文档问答、代码、对话的最佳模型可能不同</li></ul></li><li><p><strong>控制上下文长度</strong></p><ul><li>长上下文显著增加显存与延迟开销</li></ul></li><li><p><strong>合理并发</strong></p><ul><li>避免过高并发导致排队和超时</li></ul></li><li><p><strong>缓存高频请求</strong></p><ul><li>对模板化问题和固定知识问答可做结果缓存</li></ul></li><li><p><strong>监控资源</strong></p><ul><li>关注 GPU/CPU 利用率、显存、P95 延迟、失败率</li></ul></li></ol><hr><h2 id="八、典型应用场景" tabindex="-1">八、典型应用场景 <a class="header-anchor" href="#八、典型应用场景" aria-label="Permalink to &quot;八、典型应用场景&quot;">​</a></h2><ol><li><p><strong>本地知识库问答（RAG）</strong></p><ul><li>文档切片 + 向量检索 + Ollama 生成</li></ul></li><li><p><strong>私有代码助手</strong></p><ul><li>内网代码分析、提交信息生成、PR 总结</li></ul></li><li><p><strong>内部办公自动化</strong></p><ul><li>周报草拟、邮件润色、会议纪要整理</li></ul></li><li><p><strong>Agent 原型验证</strong></p><ul><li>工具调用流程、本地任务编排快速实验</li></ul></li></ol><hr><h2 id="九、常见问题与排查方向" tabindex="-1">九、常见问题与排查方向 <a class="header-anchor" href="#九、常见问题与排查方向" aria-label="Permalink to &quot;九、常见问题与排查方向&quot;">​</a></h2><h3 id="问题-1-速度慢" tabindex="-1">问题 1：速度慢 <a class="header-anchor" href="#问题-1-速度慢" aria-label="Permalink to &quot;问题 1：速度慢&quot;">​</a></h3><ul><li>模型太大、上下文过长、并发过高</li><li>先换更轻模型、缩短上下文、做请求分级</li></ul><h3 id="问题-2-回答质量不稳定" tabindex="-1">问题 2：回答质量不稳定 <a class="header-anchor" href="#问题-2-回答质量不稳定" aria-label="Permalink to &quot;问题 2：回答质量不稳定&quot;">​</a></h3><ul><li>Prompt 模板与参数（温度）不稳定</li><li>建议固定模板，关键场景做 few-shot 示例</li></ul><h3 id="问题-3-显存不足" tabindex="-1">问题 3：显存不足 <a class="header-anchor" href="#问题-3-显存不足" aria-label="Permalink to &quot;问题 3：显存不足&quot;">​</a></h3><ul><li>降模型规模、降低并发、控制上下文长度</li><li>分离高负载任务到独立机器</li></ul><h3 id="问题-4-线上可观测性不足" tabindex="-1">问题 4：线上可观测性不足 <a class="header-anchor" href="#问题-4-线上可观测性不足" aria-label="Permalink to &quot;问题 4：线上可观测性不足&quot;">​</a></h3><ul><li>增加请求日志、延迟监控、失败分类与告警</li></ul><hr><h2 id="十、小结" tabindex="-1">十、小结 <a class="header-anchor" href="#十、小结" aria-label="Permalink to &quot;十、小结&quot;">​</a></h2><ol><li>Ollama 是本地运行大模型的实用工具，适合隐私敏感和快速迭代场景。</li><li>它的核心价值在于：本地可控、上手简单、接口统一、可与现有 AI 工程体系融合。</li><li>生产落地要重点关注模型选型、上下文预算、并发控制与监控体系。</li><li>与 RAG、Agent、Tool Use 结合后，Ollama 可成为企业私有 AI 能力的重要基础设施。</li><li>最佳实践通常是“本地 + 云端”混合策略，在隐私、成本、效果之间做平衡。</li></ol><p>如果你需要构建可控、可落地、可迭代的本地 AI 应用，Ollama 是一条非常务实的起点。</p>',57)]))}const c=a(r,[["render",o]]);export{p as __pageData,c as default};
